module top(
    input wire clk,
    input wire data,
    output reg q
);
    FDSE fdse_inst (
        .C(clk),    // Clock
        .D(data),   // Data input
        .CE(1'b1),  // Clock enable
        .Q(q)      // Output
        // .S (synchronous set) port is left unconnected
    );
endmodule
